mapper.select:
/* wms-ctmaster-label-sql-oracle.xml - selectLpnLabelList */ #{GRIDPAGING_ROWNUMTYPE_TOP}
SELECT '0' AS CHK , LPN.CTKEY , CT.CTNAME , LPN.OWKEY , OW.OWNAME , LPN.LPN , 'LPN' AS LABELTYPE , LPN.PRINTYN , LPN.REPBLICTEYN , LPN.INSERTDATE , LPN.INSERTURKEY , LPN.UPDATEDATE , LPN.UPDATEURKEY FROM TWORK_INFO_IB_LPN LPN INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = LPN.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = LPN.OWKEY
ORDER BY LPN.INSERTDATE DESC , CAST(LPN.LPN AS NUMERIC) DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-ctmaster-label-sql-oracle.xml - selectLabelList */ #{GRIDPAGING_ROWNUMTYPE_TOP}
SELECT '0' AS CHK , LA.CTKEY , CT.CTNAME , LA.OWKEY , OW.OWNAME , LA.LABELNO , LA.LABELTYPE , LA.REPBLICTEYN , LA.INSERTDATE , LA.INSERTURKEY , LA.UPDATEDATE , LA.UPDATEURKEY FROM TWORK_INFO_LABEL LA INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = LA.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = LA.OWKEY
ORDER BY LA.INSERTDATE DESC , CAST(LA.LABELNO AS NUMERIC) DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-ctmaster-label-sql-oracle.xml - selectLabelPrintList */ SELECT '0' AS CHK , LA.CTKEY , CT.CTNAME , LA.OWKEY , OW.OWNAME , LA.LABELNO , LA.LABELTYPE , LA.REPBLICTEYN , LA.INSERTDATE , LA.INSERTURKEY , LA.UPDATEDATE , LA.UPDATEURKEY FROM TWORK_INFO_LABEL LA INNER JOIN TWORK_MST_CT CT ON CT.CTKEY = LA.CTKEY INNER JOIN TWORK_MST_OW OW ON OW.OWKEY = LA.OWKEY
AND LA.CTKEY = #{ctkey} AND LA.OWKEY = #{owkey} AND LA.LABELTYPE = #{labeltype}
ORDER BY CAST(LA.LABELNO AS NUMERIC) DESC LIMIT #{createQty}

mapper.update:
/* wms-ctmaster-label-sql-oracle.xml - updateLpnLabelRepblicte */
UPDATE TWORK_INFO_IB_LPN
SET REPBLICTEYN = 'Y'
  , UPDATEDATE = #{sysdate}
  , UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
  AND OWKEY = #{owkey}
  AND LPN = #{lpn}

/* wms-ctmaster-label-sql-oracle.xml - updateLabelRepblicte */
UPDATE TWORK_INFO_LABEL
   SET REPBLICTEYN = 'Y'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND LABELTYPE = #{labeltype}
   AND LABELNO = #{labelno}
